const fs=require("fs");const path=require("path");const{execSync,execFileSync}=require("child_process");const _toolCache={};function isToolAvailable(toolName){if(toolName in _toolCache)return _toolCache[toolName];try{execFileSync("which",[toolName],{stdio:"pipe",timeout:3e3});_toolCache[toolName]=true}catch(_){_toolCache[toolName]=false}return _toolCache[toolName]}async function onPostToolUse(event){try{if(event.tool!=="Write"&&event.tool!=="Edit"){return{success:true,skipped:true,reason:"Not a Write/Edit tool"}}const filePath=event.parameters.file_path;if(!fs.existsSync(filePath)){return{success:false,error:"File not found"}}const ext=path.extname(filePath);const supportedExtensions=[".java",".js",".scss",".css",".xml",".sql"];if(!supportedExtensions.includes(ext)){return{success:true,skipped:true,reason:`Unsupported file type: ${ext}`}}console.log("\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━");console.log("✨ AUTO FORMATTER (Boris Cherny PostToolUse Hook)");console.log("━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n");console.log(`📄 File: ${path.basename(filePath)}`);const results={formatted:false,linted:false,formatter:null,linter:null,issues:[],timestamp:(new Date).toISOString()};results.formatter=await runFormatter(filePath,ext);if(results.formatter.success){results.formatted=true;console.log(`✅ Formatted with: ${results.formatter.tool}`)}else{console.log(`⚠️  Formatting skipped: ${results.formatter.reason}`)}results.linter=await runLinter(filePath,ext);if(results.linter.success){results.linted=true;console.log(`✅ Linted with: ${results.linter.tool}`);if(results.linter.issues.length>0){console.log(`\n⚠️  ${results.linter.issues.length} linter issue(s) found:`);results.linter.issues.slice(0,5).forEach(issue=>{console.log(`   • ${issue}`)});if(results.linter.issues.length>5){console.log(`   ... and ${results.linter.issues.length-5} more`)}}else{console.log(`✅ No linter issues found`)}}else{console.log(`ℹ️  Linting skipped: ${results.linter.reason}`)}console.log("\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n");return{success:true,results:results}}catch(error){console.error("[AutoFormatter] Error:",error.message);return{success:false,error:error.message}}}async function runFormatter(filePath,ext){try{switch(ext){case".java":return await formatJava(filePath);case".js":return await formatJavaScript(filePath);case".scss":case".css":return await formatStylesheet(filePath);default:return{success:false,reason:`No formatter for ${ext}`}}}catch(error){return{success:false,reason:error.message}}}async function formatJava(filePath){if(!isToolAvailable("google-java-format")){return{success:false,reason:"google-java-format not installed"}}try{execFileSync("google-java-format",["--replace",filePath],{encoding:"utf-8",stdio:"pipe"});return{success:true,tool:"google-java-format"}}catch(error){return{success:false,reason:error.message}}}async function formatJavaScript(filePath){const prettierCmd=isToolAvailable("prettier")?"prettier":null;if(!prettierCmd){return{success:false,reason:"prettier not installed"}}try{execFileSync(prettierCmd,["--write",filePath],{encoding:"utf-8",stdio:"pipe"});return{success:true,tool:"prettier"}}catch(error){return{success:false,reason:error.message}}}async function formatStylesheet(filePath){const prettierCmd=isToolAvailable("prettier")?"prettier":null;if(!prettierCmd){return{success:false,reason:"prettier not installed"}}try{execFileSync(prettierCmd,["--write",filePath],{encoding:"utf-8",stdio:"pipe"});return{success:true,tool:"prettier (SCSS)"}}catch(error){return{success:false,reason:error.message}}}async function runLinter(filePath,ext){try{switch(ext){case".java":return await lintJava(filePath);case".js":return await lintJavaScript(filePath);case".scss":case".css":return await lintStylesheet(filePath);default:return{success:false,reason:`No linter for ${ext}`}}}catch(error){return{success:false,reason:error.message}}}async function lintJava(filePath){if(!isToolAvailable("checkstyle")){return{success:false,reason:"checkstyle not installed"}}try{const output=execFileSync("checkstyle",["-c","/google_checks.xml",filePath],{encoding:"utf-8",stdio:"pipe"});const issues=parseCheckstyleOutput(output);return{success:true,tool:"checkstyle",issues:issues}}catch(error){const issues=parseCheckstyleOutput(error.stdout||error.message);return{success:true,tool:"checkstyle",issues:issues}}}async function lintJavaScript(filePath){if(!isToolAvailable("eslint")){return{success:false,reason:"eslint not installed"}}try{const output=execFileSync("eslint",["--format","json",filePath],{encoding:"utf-8",stdio:"pipe"});const results=JSON.parse(output);const issues=[];if(results.length>0&&results[0].messages){results[0].messages.forEach(msg=>{issues.push(`Line ${msg.line}: ${msg.message} (${msg.ruleId})`)})}return{success:true,tool:"eslint",issues:issues}}catch(error){try{const results=JSON.parse(error.stdout||"[]");const issues=[];if(results.length>0&&results[0].messages){results[0].messages.forEach(msg=>{issues.push(`Line ${msg.line}: ${msg.message} (${msg.ruleId})`)})}return{success:true,tool:"eslint",issues:issues}}catch(e){return{success:false,reason:error.message}}}}async function lintStylesheet(filePath){if(!isToolAvailable("stylelint")){return{success:false,reason:"stylelint not installed"}}try{const output=execFileSync("stylelint",["--formatter","json",filePath],{encoding:"utf-8",stdio:"pipe"});const results=JSON.parse(output);const issues=[];if(results.length>0&&results[0].warnings){results[0].warnings.forEach(warning=>{issues.push(`Line ${warning.line}: ${warning.text}`)})}return{success:true,tool:"stylelint",issues:issues}}catch(error){return{success:false,reason:error.message}}}function parseCheckstyleOutput(output){const issues=[];const lines=output.split("\n");for(const line of lines){if(line.includes("[ERROR]")||line.includes("[WARN]")){const match=line.match(/:(\d+):\s*(.+)/);if(match){issues.push(`Line ${match[1]}: ${match[2]}`)}}}return issues}if(require.main===module){let input="";process.stdin.setEncoding("utf8");process.stdin.on("data",chunk=>{input+=chunk});process.stdin.on("end",async()=>{try{const event=JSON.parse(input);const hookEvent={tool:event.tool_name||event.tool||"",parameters:event.tool_input||event.parameters||{}};await onPostToolUse(hookEvent);process.exit(0)}catch(e){process.stderr.write(`[AutoFormatter] Parse error: ${e.message}\n`);process.exit(0)}});setTimeout(()=>{process.exit(0)},3e4)}module.exports={onPostToolUse:onPostToolUse};